    describe('permissioned realm', function () {
        let testRealm1URL = 'http://127.0.0.1:4447/test/';
        let testRealm2URL = 'http://127.0.0.1:4448/test/';
        let testRealm2: Realm;
        function setupRealms(hooks: NestedHooks, permissions: {
            consumer: RealmPermissions;
            provider: RealmPermissions;
        }) {
            setupPermissionedRealms(hooks, {
                // provider
                realms: [
                    {
                        realmURL: testRealm1URL,
                        permissions: permissions.provider,
                        fileSystem: {
                            'article.gts': `
              import { contains, field, CardDef, Component } from "https://cardstack.com/base/card-api";
              import StringField from "https://cardstack.com/base/string";
              export class Article extends CardDef {
                @field title = contains(StringField);
              }
            `,
                        },
                    },
                    // consumer
                    {
                        realmURL: testRealm2URL,
                        permissions: permissions.consumer,
                        fileSystem: {
                            'website.gts': `
              import { contains, field, CardDef, linksTo } from "https://cardstack.com/base/card-api";
              import { Article } from "${testRealm1URL}article" // importing from another realm;
              export class Website extends CardDef {
                @field linkedArticle = linksTo(Article);
              }`,
                            'website-1.json': {
                                data: {
                                    attributes: {},
                                    meta: {
                                        adoptsFrom: {
                                            module: './website',
                                            name: 'Website',
                                        },
                                    },
                                },
                            },
                        },
                    },
                ],
                onRealmSetup({ realms: [_, realm2] }) {
                    testRealm2 = realm2.realm;
                },
            });
        }
        describe('readable realm', function () {
            const hooks = {
                before: beforeAll,
                after: afterAll,
                beforeEach,
                afterEach
            };
            setupRealms(hooks, {
                provider: {
                    ['@node-test_realm:localhost']: ['read'],
                },
                consumer: {
                    '*': ['read', 'write'],
                    '@node-test_realm:localhost': ['read', 'realm-owner'],
                },
            });
            test('indexes a card from another realm when it has permission to read', async function () {
                let stats = { ...testRealm2.realmIndexUpdater.stats };
                expect(stats.fileErrors).toBe(0);
                expect(stats.instanceErrors).toBe(0);
                expect(stats.filesIndexed).toBe(2);
                expect(stats.instancesIndexed).toBe(1);
                expect(stats.totalIndexEntries).toBe(3);
            });
        });
        describe('un-readable realm', function () {
            const hooks = {
                before: beforeAll,
                after: afterAll,
                beforeEach,
                afterEach
            };
            setupRealms(hooks, {
                provider: {
                    nobody: ['read', 'write'], // Consumer's matrix user not authorized to read from provider
                },
                consumer: {
                    '*': ['read', 'write'],
                },
            });
            test('surfaces instance errors when lacking permission to read from another realm', async function () {
                // Error during indexing will be: "Authorization error: Insufficient
                // permissions to perform this action"
                let stats = { ...testRealm2.realmIndexUpdater.stats };
                expect(stats.instanceErrors).toBe(1);
                expect(stats.instancesIndexed).toBe(0);
            });
        });
    });
